"use client";

import React, { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea-inv";
import { FilePlus, Copy, Check } from "lucide-react";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Trash2, Wrench, Loader2 } from "lucide-react";
import { PatientDetails } from "./patient-details/patient-details";
import MinimalistClock from "./clock/clock";
import WaterBalanceCalculator from "@/components/water-balance/water-balance";
import AcidBaseWidget from "@/components/acid-base/acid-base";
import BMICalculator from "@/components/bmi/bmi-calculator";
import { generateHighlightedHTML } from "./utils/generateHighlightedHTML";
import References from "./references/references";
import { MedicalDisclaimer } from "@/components/medical-disclaimer";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import PrevEvolutions from "./prev-evolutions/prev-evolutions";

interface AnalysisData {
  analysis: string;
  [key: string]: any;
}

interface MedicalRecord {
  id: number;
  patientName: string;
  patientAge: string;
  date: string;
  notes: string;
  diagnosis: string;
  treatment: string;
  analysis?: AnalysisData | null;
  timestamp?: string;
}

interface ClinicalNotesUser {
  name?: string;
  surname?: string;
  specialty?: string;
  idNumber?: string;
}

interface Tool {
  value: string;
  label: string;
}

export default function ClinicalNotes() {
  const [currentRecord, setCurrentRecord] = useState<MedicalRecord>({
    id: new Date().getTime(),
    patientName: "",
    patientAge: "",
    date: new Date().toISOString().split("T")[0],
    notes: "",
    diagnosis: "",
    treatment: "",
    analysis: null,
  });

  const [allRecords, setAllRecords] = useState<MedicalRecord[]>([]);
  const [isViewingExistingRecord, setIsViewingExistingRecord] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isCopied, setIsCopied] = useState(false);

  const [user, setUser] = useState<ClinicalNotesUser | null>(null);

  useEffect(() => {
    try {
      const storedString = localStorage.getItem("clinical-notes-user");
      if (storedString) {
        setUser(JSON.parse(storedString) as ClinicalNotesUser);
      }
    } catch (err) {
      console.error(err);
    }
  }, []);

  const handleCreateNewRecord = () => {
    createNewRecord();
  };

  const [availableTools, setAvailableTools] = useState<Tool[]>([
    { value: "balance-hidrico", label: "Balance hídrico" },
    { value: "eab", label: "EAB" },
    { value: "bmi", label: "BMI" },
  ]);

  useEffect(() => {
    if (!isSaved) return;
    const timer = setTimeout(() => {
      setIsSaved(false);
    }, 1000);
    return () => clearTimeout(timer);
  }, [isSaved]);

  useEffect(() => {
    if (!isCopied) return;
    const timer = setTimeout(() => {
      setIsCopied(false);
    }, 2000);
    return () => clearTimeout(timer);
  }, [isCopied]);

  const [selectedTools, setSelectedTools] = useState<string[]>([]);

  useEffect(() => {
    let mounted = true;

    try {
      const savedRecords = localStorage.getItem("clinicalNotes");

      if (
        savedRecords &&
        savedRecords !== "undefined" &&
        savedRecords !== "null"
      ) {
        try {
          const parsedRecords = JSON.parse(savedRecords);
          if (Array.isArray(parsedRecords) && mounted) {
            setAllRecords(parsedRecords);
            return;
          }
        } catch (parseError) {
          console.warn("Error parsing saved records:", parseError);
          localStorage.removeItem("clinicalNotes");
        }
      }

      if (mounted) {
        setAllRecords([]);
      }
    } catch (error) {
      console.warn("localStorage not available:", error);
      if (mounted) {
        setAllRecords([]);
      }
    }

    return () => {
      mounted = false;
    };
  }, []);

  const updateRecordWithAnalysis = (recordId: number, analysisData: AnalysisData) => {
    setAllRecords((prevRecords) => {
      const updatedRecords = prevRecords.map((record) =>
        record.id === recordId ? { ...record, analysis: analysisData } : record,
      );

      try {
        localStorage.setItem("clinicalNotes", JSON.stringify(updatedRecords));
      } catch (error) {
        console.warn("localStorage not available:", error);
      }

      return updatedRecords;
    });

    if (currentRecord?.id === recordId) {
      setCurrentRecord((prev) => ({
        ...prev,
        analysis: analysisData.response,
      }));
    }
  };

  const copyNoteToClipboard = async () => {
    try {
      const noteHeader = `Paciente: ${currentRecord.patientName}\nEdad: ${currentRecord.patientAge} años\nFecha: ${currentRecord.date}\n\n`;
      const noteContent = currentRecord.notes.trim();
      const fullNote = noteHeader + noteContent;

      if (user?.name && user?.surname) {
        const signature = `\n\n---\nDr. ${user.surname} ${user.name}\n${user.specialty || ""}\nM.N. ${user.idNumber || ""}`;
        const completeNote = fullNote + signature;
        await navigator.clipboard.writeText(completeNote);
      } else {
        await navigator.clipboard.writeText(fullNote);
      }

      setIsCopied(true);
    } catch (error) {
      console.error("Failed to copy note to clipboard:", error);
      try {
        const textArea = document.createElement("textarea");
        const noteHeader = `Paciente: ${currentRecord.patientName}\nEdad: ${currentRecord.patientAge} años\nFecha: ${currentRecord.date}\n\n`;
        const noteContent = currentRecord.notes.trim();
        let fullNote = noteHeader + noteContent;

        if (user?.name && user?.surname) {
          const signature = `\n\n---\nDr. ${user.surname} ${user.name}\n${user.specialty || ""}\nM.N. ${user.idNumber || ""}`;
          fullNote += signature;
        }

        textArea.value = fullNote;
        document.body.appendChild(textArea);
        textArea.focus();
        textArea.select();
        document.execCommand("copy");
        document.body.removeChild(textArea);
        setIsCopied(true);
      } catch (fallbackError) {
        console.error("Fallback copy method also failed:", fallbackError);
      }
    }
  };

  const analyzeNote = async (noteText: string, recordId: number): Promise<AnalysisData | null> => {
    try {
      setIsAnalyzing(true);

      const response = await fetch("/api/noteAnalysis", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          text: noteText.trim(),
        }),
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(
          `Error ${response.status}: ${errorData.error || response.statusText}`,
        );
      }

      const result: AnalysisData = await response.json();

      if (result && recordId) {
        updateRecordWithAnalysis(recordId, result?.analysis);

        setCurrentRecord((prev) => ({
          ...prev,
          analysis: result?.analysis,
        }));
      }

      return result;
    } catch (error) {
      console.error("Error calling note analysis API:", error);
      return null;
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveRecord = async () => {
    if (currentRecord.patientName.trim() && currentRecord.notes.trim()) {
      const recordId = Date.now();
      const newRecord: MedicalRecord = {
        id: recordId,
        ...currentRecord,
        timestamp: "Just now",
      };

      setAllRecords((prevRecords) => {
        const updatedRecords = [newRecord, ...prevRecords];

        try {
          localStorage.setItem(
            "clinicalNotes",
            JSON.stringify(updatedRecords),
          );
        } catch (error) {
          console.warn("localStorage not available:", error);
        }

        return updatedRecords;
      });

      setCurrentRecord((prev) => ({
        ...prev,
        id: recordId,
      }));

      setIsSaved(true);
      setIsViewingExistingRecord(true);

      await analyzeNote(currentRecord.notes, recordId);
    }
  };

  const clearForm = () => {
    setCurrentRecord({
      id: new Date().getTime(),
      patientName: currentRecord.patientName,
      patientAge: currentRecord.patientAge,
      date: new Date().toISOString().split("T")[0],
      notes: "",
      diagnosis: "",
      treatment: "",
      analysis: null,
    });
    setIsViewingExistingRecord(false);
    setAvailableTools([
      { value: "balance-hidrico", label: "Balance hídrico" },
      { value: "eab", label: "EAB" },
      { value: "bmi", label: "BMI" },
    ]);
    setSelectedTools([]);
  };

  const loadRecord = (record: MedicalRecord) => {
    setCurrentRecord({
      id: record.id,
      patientName: record.patientName,
      patientAge: record.patientAge,
      date: record.date,
      notes: record.notes,
      diagnosis: record.diagnosis || "",
      treatment: record.treatment || "",
      analysis: record.analysis || null,
    });
    setIsViewingExistingRecord(true);
    setAvailableTools([
      { value: "balance-hidrico", label: "Balance hídrico" },
      { value: "eab", label: "EAB" },
      { value: "bmi", label: "BMI" },
    ]);
    setSelectedTools([]);
  };

  const createNewRecord = () => {
    clearForm();
  };

  useEffect(() => {
    const handleGlobalKeyDown = (e: KeyboardEvent) => {
      if (
        e.ctrlKey &&
        e.key === "Enter" &&
        !isViewingExistingRecord &&
        !isAnalyzing
      ) {
        e.preventDefault();
        const isFormValid =
          currentRecord.patientName.trim() && currentRecord.notes.trim();
        if (isFormValid) {
          saveRecord();
        }
      }

      if (e.ctrlKey && e.key === "n") {
        e.preventDefault();
        createNewRecord();
      }

      if (e.ctrlKey && e.key === "c" && e.shiftKey && currentRecord.notes.trim()) {
        e.preventDefault();
        copyNoteToClipboard();
      }

      if (e.altKey && e.key === "Enter") {
        e.preventDefault();
        createNewRecord();
      }
    };

    document.addEventListener("keydown", handleGlobalKeyDown);

    return () => {
      document.removeEventListener("keydown", handleGlobalKeyDown);
    };
  }, [currentRecord, isViewingExistingRecord, allRecords, isAnalyzing, user]);

  const handleToolSelect = (value: string) => {
    setSelectedTools((prev) => [...prev, value]);
    setAvailableTools((prev) => prev.filter((tool) => tool.value !== value));
  };

  const isFormValid =
    currentRecord.patientName.trim() && currentRecord.notes.trim();

  return (
    <div className="flex flex-col w-full h-screen">
      <div className="flex w-full py-4 px-8 flex-1">
        <div className="flex-1 flex flex-col min-w-0">
          <div className="flex items-center gap-4 p-2 border-b justify-between">
            <div className="flex-1">
              <MinimalistClock />
              <PatientDetails
                currentRecord={currentRecord}
                isSaved={isSaved}
              />
            </div>

            {currentRecord.notes.trim() && (
              <Button
                onClick={copyNoteToClipboard}
                variant="ghost"
                size="icon"
                className="relative"
                title="Copiar nota completa (Ctrl+Shift+C)"
              >
                {isCopied ? (
                  <Check className="h-4 w-4 text-green-600" />
                ) : (
                  <Copy className="h-4 w-4" />
                )}
              </Button>
            )}

            <AlertDialog>
              <AlertDialogTrigger asChild>
                <Button className="ms-2" variant="ghost" size="icon">
                  <FilePlus />
                </Button>
              </AlertDialogTrigger>
              <AlertDialogContent>
                <AlertDialogHeader>
                  <AlertDialogTitle>Crear Nueva Evolución</AlertDialogTitle>
                  <AlertDialogDescription>
                    ¿Estás seguro de que deseas crear una nueva evolución para{" "}
                    {currentRecord.patientName}? Se guardará el progreso actual
                    y se iniciará un nuevo registro.
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                  <AlertDialogCancel>Cancelar</AlertDialogCancel>
                  <AlertDialogAction onClick={handleCreateNewRecord}>
                    Crear Nueva Evolución
                  </AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>

            <PrevEvolutions allRecords={allRecords} />
          </div>
          <div className="flex-1 flex flex-col gap-4 p-4">
            <div className="flex flex-1">
              <div className="relative flex-1">
                {isAnalyzing && (
                  <div className="absolute inset-0 backdrop-blur-sm z-10 flex items-center justify-center rounded-md">
                    <div className="flex flex-col items-center gap-3">
                      <Loader2 className="h-8 w-8 animate-spin" />
                      <p className="text-sm font-medium">
                        Guardando nota médica...
                      </p>
                      <p className="text-xs text-gray-500">
                        Por favor espera mientras procesamos el contenido
                      </p>
                    </div>
                  </div>
                )}

                {currentRecord.analysis ? (
                  <div
                    className="w-[75%]"
                    style={{ fontFamily: "sans-serif", maxHeight: "500px" }}
                    dangerouslySetInnerHTML={{
                      __html: generateHighlightedHTML(
                        currentRecord.notes,
                        typeof currentRecord.analysis === "string"
                          ? JSON.parse(currentRecord.analysis)
                          : currentRecord.analysis,
                      ),
                    }}
                  />
                ) : (
                  <Textarea
                    placeholder={
                      isViewingExistingRecord
                        ? "Registro guardado - Solo lectura"
                        : "Comenzá la nota clínica acá..."
                    }
                    value={currentRecord.notes}
                    onChange={(e) =>
                      !isViewingExistingRecord &&
                      setCurrentRecord({
                        ...currentRecord,
                        notes: e.target.value,
                      })
                    }
                    className={`flex-1 resize-none w-[75%] ${
                      isViewingExistingRecord
                        ? "cursor-not-allowed opacity-75"
                        : ""
                    }`}
                    readOnly={isViewingExistingRecord}
                  />
                )}
                <div className="flex flex-col absolute bottom-0 px-3 py-2 opacity-50">
                  <span>
                    {user?.surname} {user?.name}
                  </span>
                  <small>{user?.specialty}</small>
                  <small>M.N.{user?.idNumber}</small>
                </div>
              </div>

              <div className="w-[35%] pl-6">
                <div className="flex gap-2 items-end justify-end flex-col">
                  <div className="flex items-center gap-2">
                    <Wrench className="h-4 w-4" />
                    <Select
                      onValueChange={handleToolSelect}
                      key={availableTools.length}
                    >
                      <SelectTrigger className="w-full">
                        <SelectValue placeholder="Agregar" />
                      </SelectTrigger>
                      <SelectContent>
                        {availableTools.map((tool) => (
                          <SelectItem key={tool.value} value={tool.value}>
                            {tool.label}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="py-4 flex flex-col gap-4 items-end">
                    {selectedTools.includes("balance-hidrico") && (
                      <div className="flex gap-2">
                        <WaterBalanceCalculator data={{}} />
                        {!isViewingExistingRecord && (
                          <Button
                            onClick={() => {
                              setSelectedTools(
                                selectedTools.filter(
                                  (tool) => tool !== "balance-hidrico",
                                ),
                              );
                              setAvailableTools((prev) => [
                                ...prev,
                                {
                                  value: "balance-hidrico",
                                  label: "Balance hídrico",
                                },
                              ]);
                            }}
                            variant="ghost"
                            className="h-6 w-6"
                          >
                            <Trash2 />
                          </Button>
                        )}
                      </div>
                    )}
                    {selectedTools.includes("eab") && (
                      <div className="flex gap-2">
                        <AcidBaseWidget />
                        {!isViewingExistingRecord && (
                          <Button
                            onClick={() => {
                              setSelectedTools(
                                selectedTools.filter(
                                  (tool) => tool !== "eab",
                                ),
                              );
                              setAvailableTools((prev) => [
                                ...prev,
                                { value: "eab", label: "EAB" },
                              ]);
                            }}
                            variant="ghost"
                            className="h-6 w-6"
                          >
                            <Trash2 />
                          </Button>
                        )}
                      </div>
                    )}
                    {selectedTools.includes("bmi") && (
                      <div className="flex gap-2">
                        <BMICalculator />
                        {!isViewingExistingRecord && (
                          <Button
                            onClick={() => {
                              setSelectedTools(
                                selectedTools.filter(
                                  (tool) => tool !== "bmi",
                                ),
                              );
                              setAvailableTools((prev) => [
                                ...prev,
                                { value: "bmi", label: "BMI" },
                              ]);
                            }}
                            variant="ghost"
                            className="h-6 w-6"
                          >
                            <Trash2 />
                          </Button>
                        )}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>

            <div className="flex gap-3 pt-4 justify-end"></div>
          </div>
        </div>
      </div>
      <div className="absolute bottom-0 p-2">
        {currentRecord.analysis && <References />}
        <MedicalDisclaimer />
      </div>
    </div>
  );
}

"use client";

import ClinicalNotes from "./clinical-notes";

export default function ClinicalNotesPage() {
  return <ClinicalNotes />;
}

import React, { useState, useEffect } from "react";
import { Card, CardContent } from "@/components/ui/card";

export default function MinimalistClock() {
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentTime(new Date());
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  const formatTime = (date) => {
    return date.toLocaleTimeString("en-US", {
      hour: "numeric",
      minute: "2-digit",
      hour12: true,
    });
  };

  const formatDate = (date) => {
    return date.toLocaleDateString("en-US", {
      weekday: "long",
      year: "numeric",
      month: "long",
      day: "numeric",
    });
  };

  // const getTimezone = (date) => {
  //   return date
  //     .toLocaleDateString("en-US", {
  //       timeZoneName: "short",
  //     })
  //     .split(", ")[1];
  // };

  return (
      <div className="flex gap-1 items-baseline text-xs opacity-50">
        <div className="">
          {formatTime(currentTime)}
        </div>
        <div>{formatDate(currentTime)}</div>
      </div>
  );
}

import { Save } from "lucide-react";
import { Badge } from "@/components/ui/badge";

interface PatientDetailsProps {
  currentRecord: {
    patientName: string;
    patientAge: string;
  };
  isSaved: boolean;
}

export const PatientDetails = ({ currentRecord, isSaved }: PatientDetailsProps) => {
  return (
    <div className="flex gap-6 items-center justify-between w-full">
      <div className="flex items-baseline gap-2">
        <span>{currentRecord.patientName}</span>
        {currentRecord.patientAge && (
          <small className="opacity-50">{currentRecord.patientAge} años</small>
        )}
      </div>
      {isSaved && (
        <Badge>
          <Save /> Guardado!
        </Badge>
      )}
    </div>
  );
};

import {
  Drawer,
  DrawerClose,
  DrawerContent,
  DrawerDescription,
  DrawerHeader,
  DrawerTitle,
  DrawerTrigger,
} from "@/components/ui/drawer";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { Eye, Calendar, FileText, X, FileClock } from "lucide-react";

const PrevEvolutions = ({ allRecords }) => {
  const previousRecords = allRecords?.slice(1) || [];

  if (!previousRecords.length) {
    return null;
  }

  const formatDate = (dateString) => {
    try {
      return new Date(dateString).toLocaleDateString('es-ES', {
        year: 'numeric',
        month: 'short',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      });
    } catch {
      return dateString;
    }
  };

  return (
    <Drawer>
      <DrawerTrigger asChild>
        <Button variant="ghost" className="gap-2" size="icon">
         <FileClock/>
        </Button>
      </DrawerTrigger>
      <DrawerContent className="max-h-[85vh]">
        <DrawerHeader className="border-b">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <FileText className="h-5 w-5 text-muted-foreground" />
              <div>
                <DrawerTitle>Evoluciones médicas previas</DrawerTitle>
                <DrawerDescription>
                  Historial de {previousRecords.length - 1} {previousRecords.length === 1 ? 'nota previa' : 'notas previas'}
                </DrawerDescription>
              </div>
            </div>
            <DrawerClose asChild>
              <Button variant="ghost" size="sm" className="gap-2">
                <X className="h-4 w-4" />
                Cerrar
              </Button>
            </DrawerClose>
          </div>
        </DrawerHeader>

        <div className="flex-1 overflow-y-auto p-4 max-h-[60vh]">
          <div className="space-y-4">
            {previousRecords.map((record, index) => (
              <div key={index} className="space-y-3">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <Calendar className="h-4 w-4 text-muted-foreground" />
                    <span className="font-medium">
                      {formatDate(record.date)}
                    </span>
                  </div>
                  {index === 0 && (
                    <Badge variant="default">Más reciente</Badge>
                  )}
                </div>

                <div className="bg-muted/50 rounded-lg p-4">
                  <div className="whitespace-pre-wrap text-sm leading-relaxed">
                    {record.notes || "Sin notas disponibles"}
                  </div>
                </div>

                {index < previousRecords.length - 1 && (
                  <Separator className="my-4" />
                )}
              </div>
            ))}
          </div>
        </div>
      </DrawerContent>
    </Drawer>
  );
};

export default PrevEvolutions;

import { Badge } from "@/components/ui/badge";

const References = () => {
  const legendItems = [
    {
      section: "Motivo de consulta",
      colorClass: "bg-blue-500/30  text-foreground dark:text-blue-200",
    },
    {
      section: "Enfermedad actual",
      colorClass: "bg-amber-500/30 text-foreground dark:text-amber-200",
    },
    {
      section: "Antecedentes personales", 
      colorClass: "bg-green-500/30 text-foreground dark:text-green-200",
    },
    {
      section: "Examen físico",
      colorClass: "bg-purple-500/30 text-foreground darK:text-purple-200",
    },
    {
      section: "Tratamiento iniciado",
      colorClass: "bg-cyan-500/30  text-foreground dar:text-cyan-200",
    }
  ];

  return (
    <div className="flex-1">
      <div className="flex flex-wrap gap-3 items-center justify-end">
        {legendItems.map((item, index) => (
          <Badge key={index} className={`${item.colorClass} font-medium`}>
            {item.section}
          </Badge>
        ))}
      </div>
    </div>
  );
};

export default References;

/* eslint-disable @typescript-eslint/no-explicit-any */

// Define proper types for the function parameters and return values
interface AnalysisData {
  analysis: string | object;
  [key: string]: any;
}

interface TermsByCategory {
  [category: string]: string[];
}

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

export function generateHighlightedHTML(noteText: string, jsonData: AnalysisData): string {
  // Sanitize the note text before any HTML insertion
  const sanitizedText = escapeHtml(noteText);

  // Extract terms with their categories
  const termsByCategory = extractTermsByCategory(jsonData);

  // Highlight all terms in the sanitized text
  const highlightedContent = highlightTerms(sanitizedText, termsByCategory);

  return `
    <div class="max-w-4xl mx-auto p-4">
      <div class="whitespace-pre-wrap leading-relaxed">${highlightedContent}</div>
    </div>
  `;
}

function extractTermsByCategory(data: any): TermsByCategory {
  const termsByCategory: TermsByCategory = {};

  function extractFromValue(value: any, category: string): void {
    if (typeof value === 'string' && value.trim().length > 1) {
      if (!termsByCategory[category]) termsByCategory[category] = [];
      termsByCategory[category].push(value.trim());
    } else if (typeof value === 'number') {
      if (!termsByCategory[category]) termsByCategory[category] = [];
      termsByCategory[category].push(value.toString());
    } else if (Array.isArray(value)) {
      value.forEach(item => extractFromValue(item, category));
    } else if (typeof value === 'object' && value !== null) {
      // Only use first-level category, don't create sub-categories
      Object.values(value).forEach(val => extractFromValue(val, category));
    }
  }

  Object.entries(data).forEach(([key, value]) => {
    extractFromValue(value, key);
  });

  // Remove duplicates from each category
  Object.keys(termsByCategory).forEach(category => {
    termsByCategory[category] = [...new Set(termsByCategory[category])];
  });

  return termsByCategory;
}

function highlightTerms(text: string, termsByCategory: TermsByCategory): string {
  let result = text;

  // Color mapping for different categories - simplified to first-order properties only
  const categoryColors: { [key: string]: string } = {
    'chief_complaint': 'bg-blue-500/30 text-foreground dark:text-blue-200',
    'present_illness': 'bg-amber-500/30 text-foreground dark:text-amber-200',
    'personal_history': 'bg-green-500/30  text-foreground dark:text-green-200',
    'physical_exam': 'bg-purple-500/30 text-foreground dark:text-purple-200',
    'treatment_started': 'bg-cyan-500/30 text-foreground dark:text-cyan-200',
    'surgery_performed': 'bg-teal-500/30 text-foreground dark:text-teal-200',
    'default': 'bg-yellow-500/30  text-foreground dark:text-yellow-200'
  };

  // Section headers to avoid highlighting
  const sectionHeaders: RegExp[] = [
    /motivo\s+de\s+consulta/i,
    /enfermedad\s+actual/i,
    /antecedentes\s+personales/i,
    /examen\s+físico/i
  ];

  // Sort categories by term length to avoid partial matches
  const sortedCategories = Object.entries(termsByCategory).map(([category, terms]) => ({
    category,
    terms: (terms as string[]).sort((a, b) => b.length - a.length)
  }));

  sortedCategories.forEach(({ category, terms }) => {
    const colorClass = categoryColors[category] || categoryColors.default;

    terms.forEach((term: string) => {
      if (!term) return;

      // Skip section headers
      const isHeader = sectionHeaders.some(pattern => pattern.test(term));
      if (isHeader) return;

      // Create regex to find the term - escape special characters
      const escapedTerm = term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      const regex = new RegExp(`\\b${escapedTerm}\\b`, 'gi');

      // Replace with highlighted version
      result = result.replace(regex, (match: string, offset: number, string: string) => {
        // Don't highlight if already inside a span tag
        const beforeMatch = string.substring(0, offset);
        const openSpans = (beforeMatch.match(/<span/g) || []).length;
        const closeSpans = (beforeMatch.match(/<\/span>/g) || []).length;

        if (openSpans > closeSpans) return match;

        // Don't highlight section headers
        const context = string.substring(Math.max(0, offset - 20), offset + match.length + 20);
        const inHeader = sectionHeaders.some(pattern => pattern.test(context));
        if (inHeader) return match;

        return `<span class="${colorClass} px-1 rounded font-medium">${match}</span>`;
      });
    });
  });

  return result;
}
